package com.xwc.open.easybatis.core.support.table;import com.xwc.open.easybatis.core.anno.table.Id;import com.xwc.open.easybatis.core.commons.AnnotationUtils;import com.xwc.open.easybatis.core.enums.IdType;/** * 创建人：徐卫超 * 时间：2019/8/3 16:35 * 功能：主键描述对象 */public class PrimaryKey extends ColumnMeta {    private IdType idType;    public PrimaryKey(ColumnMeta columnMeta, IdType idType, Id id) {        super(columnMeta);        this.idType = idType;        if (idType == IdType.AUTO) {            this.setInsertIgnore(true);        }        this.mergeTableAnnotation(AnnotationUtils.getAnnotationAttributes(id));    }}